async function o(t){return $fetch("/api/products",{params:t})}async function u(t){return $fetch(`/api/products/${t}`)}async function e(t){return $fetch("/api/products",{method:"POST",body:t})}async function r(t,c){return $fetch(`/api/products/${t}`,{method:"PATCH",body:c})}async function a(t){await $fetch(`/api/products/${t}`,{method:"DELETE"})}async function n(t){return $fetch("/api/products/lookup",{params:t})}export{o as a,u as b,e as c,a as d,n as f,r as u};
